import React, { useState } from 'react';
import { NavigationContainer } from '@react-navigation/native';
import { createBottomTabNavigator } from '@react-navigation/bottom-tabs';
import { createNativeStackNavigator } from '@react-navigation/native-stack';
import { Text, View, Button, StyleSheet } from 'react-native';

// Import Screens
import StudentDashboard from './src/screens/StudentDashboard';
import RiderDashboard from './src/screens/RiderDashboard';
import ChatScreen from './src/screens/ChatScreen';

const Tab = createBottomTabNavigator();
const Stack = createNativeStackNavigator();

// Mock Auth wrapper for demonstration
export default function App() {
  const [role, setRole] = useState(null); // 'student' or 'rider'

  if (!role) {
    return (
      <View style={styles.authContainer}>
        <Text style={styles.title}>Welcome to Campus Eats</Text>
        <Text style={{ marginBottom: 20 }}>Select your role to sign in:</Text>
        <View style={styles.btnGroup}>
            <Button title="Login as Student" onPress={() => setRole('student')} />
            <View style={{ height: 10 }} />
            <Button title="Login as Rider" color="#10b981" onPress={() => setRole('rider')} />
        </View>
      </View>
    );
  }

  return (
    <NavigationContainer>
      <Stack.Navigator screenOptions={{ headerShown: false }}>
        {role === 'student' ? (
          <Stack.Screen name="StudentRoot" component={StudentTabs} />
        ) : (
          <Stack.Screen name="RiderRoot" component={RiderTabs} />
        )}
        <Stack.Screen name="Chat" component={ChatScreen} options={{ headerShown: true, title: 'Live Chat' }} />
      </Stack.Navigator>
    </NavigationContainer>
  );
}

function StudentTabs() {
  return (
    <Tab.Navigator>
      <Tab.Screen name="Order Food" component={StudentDashboard} />
    </Tab.Navigator>
  );
}

function RiderTabs() {
  return (
    <Tab.Navigator>
      <Tab.Screen name="Deliveries" component={RiderDashboard} />
    </Tab.Navigator>
  );
}

const styles = StyleSheet.create({
  authContainer: { flex: 1, justifyContent: 'center', alignItems: 'center', padding: 20, backgroundColor: '#f1f5f9' },
  title: { fontSize: 24, fontWeight: 'bold', marginBottom: 10, color: '#0f172a' },
  btnGroup: { width: '80%' }
});
